using System.IO;
using System.Text;
using System.Windows;
using System.Windows.Controls;
using System.Windows.Input;
using System.Collections.Generic;
using Quicker.Public;
using Quicker.Utilities;

static Window _win;
static IDictionary<string, object> _dataContext;
static ICustomWindowContext _winContext;
static System.Windows.Controls.TextBox _editor;
static TextBlock _filePathText;
static TextBlock _statusText;

static string _filePath;
static string _originalContent;

public static void OnWindowCreated(Window win, IDictionary<string, object> dataContext, ICustomWindowContext winContext)
{
    _win = win;
    _dataContext = dataContext;
    _winContext = winContext;

    _filePath = GetSelectedFilePath();
    if (string.IsNullOrEmpty(_filePath))
    {
        Microsoft.Win32.OpenFileDialog dlg = new Microsoft.Win32.OpenFileDialog();
        dlg.Filter = "文本文件|*.txt;*.log;*.md;*.json;*.xml;*.csv;*.ini;*.cfg;*.yml;*.yaml;*.toml;*.css;*.js;*.html;*.py;*.cs;*.java;*.cpp;*.h|所有文件|*.*";
        dlg.Title = "选择要编辑的文件";
        if (dlg.ShowDialog() != true)
        {
            win.Close();
            return;
        }
        _filePath = dlg.FileName;
    }

    if (!System.IO.File.Exists(_filePath))
    {
        AppHelper.ShowError("文件不存在: " + _filePath, false);
        win.Close();
        return;
    }
}

public static void OnWindowLoaded(Window win, IDictionary<string, object> dataContext, ICustomWindowContext winContext)
{
    if (string.IsNullOrEmpty(_filePath)) return;

    _editor = win.FindName("Editor") as System.Windows.Controls.TextBox;
    _filePathText = win.FindName("FilePathText") as TextBlock;
    _statusText = win.FindName("StatusText") as TextBlock;

    _filePathText.Text = _filePath;
    win.Title = System.IO.Path.GetFileName(_filePath) + " - 文件编辑器";

    try
    {
        _originalContent = System.IO.File.ReadAllText(_filePath, Encoding.UTF8);
        _editor.Text = _originalContent;
        UpdateStatus();
    }
    catch (Exception ex)
    {
        AppHelper.ShowError("读取文件失败: " + ex.Message, false);
        win.Close();
        return;
    }

    _editor.TextChanged += OnTextChanged;
    win.PreviewKeyDown += OnWindowKeyDown;
}

static void OnTextChanged(object sender, TextChangedEventArgs e)
{
    UpdateStatus();
}

static void UpdateStatus()
{
    if (_editor == null || _statusText == null) return;
    string text = _editor.Text;
    int lines = text.Split('\n').Length;
    int chars = text.Length;
    string modified = _editor.Text != _originalContent ? " (已修改)" : "";
    _statusText.Text = string.Format("{0} 行, {1} 字符{2}", lines, chars, modified);
}

static string GetSelectedFilePath()
{
    try
    {
        Type shellType = Type.GetTypeFromProgID("Shell.Application");
        if (shellType == null) return null;
        object shell = Activator.CreateInstance(shellType);
        object windows = shellType.InvokeMember("Windows", System.Reflection.BindingFlags.InvokeMethod, null, shell, null);

        IntPtr hwnd = _win != null ? new System.Windows.Interop.WindowInteropHelper(_win).Handle : IntPtr.Zero;

        System.Collections.IEnumerable shellWindows = windows as System.Collections.IEnumerable;
        if (shellWindows == null) return null;

        foreach (object ie in shellWindows)
        {
            if (ie == null) continue;
            Type ieType = ie.GetType();

            object locationURL = ieType.InvokeMember("LocationURL", System.Reflection.BindingFlags.GetProperty, null, ie, null);
            if (locationURL == null) continue;

            string url = locationURL.ToString();
            if (!url.StartsWith("file:///")) continue;

            object selectedItems = ieType.InvokeMember("Document", System.Reflection.BindingFlags.GetProperty, null, ie, null);
            if (selectedItems == null) continue;

            Type docType = selectedItems.GetType();
            object items = docType.InvokeMember("SelectedItems", System.Reflection.BindingFlags.InvokeMethod, null, selectedItems, null);
            if (items == null) continue;

            System.Collections.IEnumerable itemsEnum = items as System.Collections.IEnumerable;
            if (itemsEnum == null) continue;

            foreach (object item in itemsEnum)
            {
                if (item == null) continue;
                Type itemType = item.GetType();
                object path = itemType.InvokeMember("Path", System.Reflection.BindingFlags.GetProperty, null, item, null);
                if (path != null)
                {
                    string filePath = path.ToString();
                    if (System.IO.File.Exists(filePath))
                    {
                        return filePath;
                    }
                }
            }
        }
    }
    catch
    {
    }
    return null;
}

static void OnWindowKeyDown(object sender, KeyEventArgs e)
{
    if (e.Key == Key.Escape)
    {
        if (_editor != null && _editor.Text != _originalContent)
        {
            MessageBoxResult r = System.Windows.MessageBox.Show("文件已修改，确定放弃更改？", "确认",
                MessageBoxButton.YesNo, MessageBoxImage.Question);
            if (r != MessageBoxResult.Yes) return;
        }
        _win.Close();
        e.Handled = true;
        return;
    }

    if (e.Key == Key.S && (Keyboard.Modifiers & ModifierKeys.Control) == ModifierKeys.Control)
    {
        SaveFile();
        e.Handled = true;
    }
}

public static bool OnButtonClicked(string controlName, object controlTag, Window win,
    IDictionary<string, object> dataContext, ICustomWindowContext winContext)
{
    string tag = controlTag != null ? controlTag.ToString() : "";

    if (tag == "cancel")
    {
        if (_editor != null && _editor.Text != _originalContent)
        {
            MessageBoxResult r = System.Windows.MessageBox.Show("文件已修改，确定放弃更改？", "确认",
                MessageBoxButton.YesNo, MessageBoxImage.Question);
            if (r != MessageBoxResult.Yes) return true;
        }
        win.Close();
        return false;
    }

    if (tag == "save")
    {
        SaveFile();
        return true;
    }

    return true;
}

static void SaveFile()
{
    try
    {
        System.IO.File.WriteAllText(_filePath, _editor.Text, Encoding.UTF8);
        _originalContent = _editor.Text;
        UpdateStatus();
        AppHelper.ShowSuccess("已保存");
        _statusText.Text = _statusText.Text + " - 已保存";
    }
    catch (Exception ex)
    {
        AppHelper.ShowError("保存失败: " + ex.Message, false);
    }
